import{constants}from"./constants.js";import{ChartGroup}from"./chart-group.js";class ChartRegistry{constructor(){this._chartMap={}}chartGroup(t){return t=t||constants.DEFAULT_CHART_GROUP,this._chartMap[t]||(this._chartMap[t]=new ChartGroup),this._chartMap[t]}has(t){for(const r in this._chartMap)if(this._chartMap.hasOwnProperty(r)&&this._chartMap[r].has(t))return!0;return!1}clear(t){if(t)this._chartMap[t]&&(this._chartMap[t].clear(),delete this._chartMap[t]);else{for(const r in this._chartMap)this._chartMap.hasOwnProperty(r)&&this._chartMap[r].clear();this._chartMap={}}}list(t){return this.chartGroup(t).list()}}const chartRegistry=new ChartRegistry;export{chartRegistry};